package kr.co.iei.auth.model.dao; import kr.co.iei.member.model.vo.Member; import lombok.RequiredArgsConstructor; import org.apache.ibatis.session.SqlSession; import org.springframework.stereotype.Repository; import java.util.Map; @Repository @RequiredArgsConstructor public class AuthDao { private final SqlSession sqlSession; public Member selectByLoginId(String loginId){ return sqlSession.selectOne("auth.selectByLoginId", loginId);} public Member selectByEmail(String email){ return sqlSession.selectOne("auth.selectByEmail", email);} public Member selectByNickname(String nickname){ return sqlSession.selectOne("auth.selectByNickname", nickname);} public int insertMember(Member member){ return sqlSession.insert("auth.insertMember", member);} public int insertUserSport(Long userId, Long sportId){ return sqlSession.insert("auth.insertUserSport", Map.of("userId",userId,"sportId",sportId)); }}
